1	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with $k$-module coefficients}
2	\label{chap:Cohomology_MayerVietoris}
3	
4	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in $k$-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers $H^n(X,\mathcal F)$ and $H^{\prime n}(U,\mathcal F)$ live in Chapter~\ref{chap:Cohomology_StructureSheafModuleK} and are imported here.
5	
6	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of $H^1(C,\mathcal O_C)$ in Definition~\ref{def:genus}.
7	
8	\section{Functoriality of cohomology in the open variable}
9	\label{sec:hmodule_prime_cohomologyPresheaf}
10	
11	The cohomology-of-an-open carrier $H^{\prime n}(X,\mathcal F)$ is contravariantly functorial in the open variable $X$. Assembling this functoriality yields a presheaf
12	\[
13	  X \longmapsto H^{\prime n}(X, \mathcal F),
14	\]
15	and, varying $\mathcal F$ as well, a bifunctor from sheaves of $k$-modules to presheaves of abelian groups. The codomain is the category of abelian groups because $\Ext$ is always valued there, regardless of the linear enrichment of the source category; the per-fiber $k$-module structure is inherited from the reducible wrapper on $H^{\prime n}$.
16	
17	\begin{definition}\leanok
18	[Cohomology presheaf functor, $H'$ flavor]
19	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
20	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
21	  \uses{def:Scheme_HModule_prime, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
22	  Let $k$ be a field, $C$ a category equipped with a Grothendieck topology $J$, and assume sheafification and $\Ext$ exist for sheaves of $k$-modules on $J$. For $n \in \mathbb N$, define the cohomology presheaf functor
23	  \[
24	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
25	  \]
26	  by the standard composition of the Yoneda embedding, the free-$k$-module functor, sheafification, and the $n$-th $\Ext$ functor.
27	\end{definition}
28	
29	\begin{proof}
30	  \uses{def:Scheme_HModule_prime}
31	  \leanok
32	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
33	\end{proof}
34	
35	\begin{definition}\leanok
36	[Cohomology presheaf, $H'$ flavor]
37	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
38	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
39	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
40	  In the setting of Definition~\ref{def:Scheme_HModule_prime_cohomologyPresheafFunctor}, let $\mathcal F$ be a sheaf of $k$-modules. For $n \in \mathbb N$, define the cohomology presheaf
41	  \[
42	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
43	  \]
44	  to be the evaluation of the bifunctor at $\mathcal F$.
45	\end{definition}
46	
47	\begin{proof}
48	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
49	  \leanok
50	  Direct evaluation of the bifunctor at $\mathcal F$.
51	\end{proof}
52	
53	\begin{remark}
54	  For every object $X$ of $C$, the underlying type of $\mathcal H^{\prime n}(\mathcal F)(X)$ is definitionally equal to $H^{\prime n}(X, \mathcal F)$. The per-fiber $k$-module structure is therefore inherited through the $H'$ wrapper.
55	\end{remark}
56	
57	\begin{remark}[Lean implementation]
58	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level $H'$ carrier.
59	\end{remark}
60	
61	\section{Mayer--Vietoris long exact sequence}
62	\label{sec:hmodule_prime_mayer_vietoris}
63	
64	A Mayer--Vietoris square for a Grothendieck topology $J$ on a category $C$ is a pullback square
65	% NOTE: rendered as a 2x2 array for KaTeX (leanblueprint web); the PDF
66	% build renders the same data via tikz-cd if the package is available.
67	\[
68	  \begin{array}{ccc}
69	    X_1 & \longrightarrow & X_2 \\
70	    \downarrow & & \downarrow \\
71	    X_3 & \longrightarrow & X_4
72	  \end{array}
73	\]
74	that is a $J$-cover: the pair of morphisms $X_2 \to X_4$ and $X_3 \to X_4$ is a covering family, and $X_1$ is the pullback. For a sheaf $\mathcal F$, the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
75	
76	\subsection{The restriction maps}
77	
78	\begin{definition}\leanok
79	[Sum of two restriction maps]
80	  \label{def:Scheme_HModule_prime_toBiprod}
81	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
82	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
83	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n \in \mathbb N$. Define the morphism
84	  \[
85	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
86	  \]
87	  to be the biproduct lift of the two restriction maps induced by $X_2 \to X_4$ and $X_3 \to X_4$.
88	\end{definition}
89	
90	\begin{proof}
91	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
92	  \leanok
93	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
94	\end{proof}
95	
96	\begin{definition}\leanok
97	[Difference of two restriction maps]
98	  \label{def:Scheme_HModule_prime_fromBiprod}
99	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
100	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
101	  In the same setting, define the morphism
102	  \[
103	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
104	  \]
105	  to be the biproduct desc of the restriction map $X_1 \to X_2$ and the additive inverse of the restriction map $X_1 \to X_3$.
106	\end{definition}
107	
108	\begin{proof}
109	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
110	  \leanok
111	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.
112	\end{proof}
113	
114	\begin{lemma}\leanok
115	[Composition vanishes]
116	  \label{lem:Scheme_HModule_prime_toBiprod_fromBiprod}
117	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_fromBiprod}
118	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
119	  In the setting above,
120	  \[
121	    \fromBiprod \circ \toBiprod \;=\; 0.
122	  \]
123	\end{lemma}
124	
125	\begin{proof}
126	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
127	  \leanok
128	  This is a formal consequence of the biproduct universal property, preadditivity, and the pullback equation $X_1 \to X_2 \to X_4 = X_1 \to X_3 \to X_4$. Every step is independent of the value category and transfers verbatim from the abelian-group-valued setting.
129	\end{proof}
130	
131	\subsection{The short exact sequence of sheaves}
132	
133	The connecting homomorphism of the Mayer--Vietoris sequence is built from a short exact sequence of sheaves of $k$-modules obtained by sheafifying the Yoneda embedding composed with the free-$k$-module functor.
134	
135	\begin{definition}\leanok
136	[Free-$k$-module functor is left adjoint]
137	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
138	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
139	  Let $k$ be a field. The free-$k$-module functor $\Type \to \ModuleCat\,k$ is a left adjoint.
140	\end{definition}
141	
142	\begin{proof}
143	  \leanok
144	  The adjunction is the standard free-forgetful adjunction for $k$-modules. The declaration packages the existing adjunction into the typeclass-witness form.
145	\end{proof}
146	
147	\begin{lemma}\leanok
148	[Pushout of free sheaves]
149	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
150	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
151	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
152	  Let $S$ be a Mayer--Vietoris square. The image of $S$ under the composite functor
153	  \[
154	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
155	  \]
156	  is a pushout square in the category of sheaves of $k$-modules.
157	\end{lemma}
158	
159	\begin{proof}
160	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
161	  \leanok
162	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-$k$-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
163	\end{proof}
164	
165	\begin{definition}\leanok
166	[Short complex of free sheaves]
167	  \label{def:Scheme_HModule_prime_shortComplex}
168	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
169	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
170	  In the setting of Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}, define the short complex of sheaves of $k$-modules
171	  \[
172	    \mathcal F_1 \xrightarrow{\;f\;} \mathcal F_2 \oplus \mathcal F_3 \xrightarrow{\;g\;} \mathcal F_4,
173	  \]
174	  where $f$ is the biproduct lift of the two maps induced by $X_1 \to X_2$ and $-X_1 \to X_3$, and $g$ is the biproduct desc of the two maps induced by $X_2 \to X_4$ and $X_3 \to X_4$. The composition $g \circ f = 0$ follows from the cokernel-cofork condition of the pushout.
175	\end{definition}
176	
177	\begin{proof}
178	  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
179	  \leanok
180	  The five object and morphism fields are filled directly from the pushout data; the zero field follows from the cokernel cofork condition.
181	\end{proof}
182	
183	\begin{definition}\leanok
184	[Free-$k$-module functor preserves monomorphisms]
185	  \label{def:Scheme_ModuleCat_free_preservesMonomorphisms}
186	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_preservesMonomorphisms}
187	  Let $k$ be a field. The free-$k$-module functor preserves monomorphisms.
188	\end{definition}
189	
190	\begin{proof}
191	  \leanok
192	  An injective function between types induces an injective $k$-linear map on free modules because the map on finsupp supports is injective. Monomorphism status in the category of $k$-modules is equivalent to injectivity.
193	\end{proof}
194	
195	\begin{lemma}\leanok
196	[The first map is mono]
197	  \label{lem:Scheme_HModule_prime_shortComplex_f_mono}
198	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_f_mono}
199	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
200	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the first map $f$ is a monomorphism.
201	\end{lemma}
202	
203	\begin{proof}
204	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
205	  \leanok
206	  The map $f$ followed by the second projection is the free-$k$-module functor applied to the monomorphism $X_1 \to X_3$, which is mono because the free functor preserves monomorphisms. Hence $f$ itself is mono.
207	\end{proof}
208	
209	\begin{lemma}\leanok
210	[The second map is epi]
211	  \label{lem:Scheme_HModule_prime_shortComplex_g_epi}
212	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_g_epi}
213	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
214	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the second map $g$ is an epimorphism.
215	\end{lemma}
216	
217	\begin{proof}
218	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
219	  \leanok
220	  By the pushout lemma, $g$ is the cokernel of $f$, and every cokernel is epi.
221	\end{proof}
222	
223	\begin{lemma}\leanok
224	[Exactness at the middle term]
225	  \label{lem:Scheme_HModule_prime_shortComplex_exact}
226	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_exact}
227	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
228	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, exactness holds at the middle term: the image of $f$ equals the kernel of $g$.
229	\end{lemma}
230	
231	\begin{proof}
232	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
233	  \leanok
234	  By the pushout lemma, $g$ is the cokernel of $f$; a map is its own kernel's cokernel in an abelian category, so exactness holds at the middle term.
235	\end{proof}
236	
237	\begin{lemma}\leanok
238	[The short complex is short exact]
239	  \label{lem:Scheme_HModule_prime_shortComplex_shortExact}
240	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_shortExact}
241	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
242	  The short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex} is short exact: its first map is mono, its second map is epi, and exactness holds at the middle term.
243	\end{lemma}
244	
245	\begin{proof}
246	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
247	  \leanok
248	  Combine Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_f_mono}, Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_g_epi}, and Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_exact}.
249	\end{proof}
250	
251	\subsection{The connecting homomorphism and the long exact sequence}
252	
253	\begin{definition}\leanok
254	[Connecting homomorphism]
255	  \label{def:Scheme_HModule_prime_delta}
256	  \lean{AlgebraicGeometry.Scheme.HModule'_δ}
257	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, lem:Scheme_HModule_prime_shortComplex_shortExact}
258	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n_0, n_1 \in \mathbb N$ with $n_0 + 1 = n_1$. The connecting homomorphism
259	  \[
260	    \delta \;:\; H^{\prime n_0}(X_1, \mathcal F) \longrightarrow H^{\prime n_1}(X_4, \mathcal F)
261	  \]
262	  is obtained by precomposing the extension class of the short exact sequence of Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_shortExact} with the canonical degree-zero map.
263	\end{definition}
264	
265	\begin{proof}
266	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, lem:Scheme_HModule_prime_shortComplex_shortExact}
267	  \leanok
268	  The extension class lives in $\Ext^1$ of the short exact sequence; precomposing with a map of degree zero and transporting through the additive structure yields the connecting homomorphism as a morphism of abelian groups.
269	\end{proof}
270	
271	\begin{definition}\leanok
272	[Mayer--Vietoris long exact sequence]
273	  \label{def:Scheme_HModule_prime_sequence}
274	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence}
275	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
276	  In the setting of Definition~\ref{def:Scheme_HModule_prime_delta}, define the five-term Mayer--Vietoris sequence
277	  \[
278	    H^{\prime n_0}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_0}(X_2, \mathcal F) \oplus H^{\prime n_0}(X_3, \mathcal F) \xrightarrow{\;\fromBiprod\;} H^{\prime n_0}(X_1, \mathcal F) \xrightarrow{\;\delta\;} H^{\prime n_1}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_1}(X_2, \mathcal F) \oplus H^{\prime n_1}(X_3, \mathcal F).
279	  \]
280	\end{definition}
281	
282	\begin{proof}
283	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
284	  \leanok
285	  The sequence is packaged as five composable arrows in the category of abelian groups.
286	\end{proof}
287	
288	\subsection{Comparison with the $\Ext$ contravariant sequence}
289	
290	The following four lemmas bridge the biproduct structure on the abelian-group side with the $\Ext$ biproduct additivity, preparing the comparison isomorphism.
291	
292	\begin{lemma}\leanok
293	[Elementwise formula for $\toBiprod$]
294	  \label{lem:Scheme_HModule_prime_toBiprod_apply}
295	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_apply}
296	  \uses{def:Scheme_HModule_prime_toBiprod}
297	  For $y \in H^{\prime n}(X_4, \mathcal F)$,
298	  \[
299	    \toBiprod(y) \;=\; \bigl(\mathrm{restriction}_{X_4 \to X_2}(y),\; \mathrm{restriction}_{X_4 \to X_3}(y)\bigr).
300	  \]
301	\end{lemma}
302	
303	\begin{proof}
304	  \uses{def:Scheme_HModule_prime_toBiprod}
305	  \leanok
306	  Follows from the definition of $\toBiprod$ as a biproduct lift and the naturality of the biproduct isomorphism with the product.
307	\end{proof}
308	
309	\begin{lemma}\leanok
310	[Elementwise formula for $\fromBiprod$]
311	  \label{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
312	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_biprodIsoProd_inv_apply}
313	  \uses{def:Scheme_HModule_prime_fromBiprod}
314	  For $y_2 \in H^{\prime n}(X_2, \mathcal F)$ and $y_3 \in H^{\prime n}(X_3, \mathcal F)$,
315	  \[
316	    \fromBiprod(y_2, y_3) \;=\; \mathrm{restriction}_{X_2 \to X_1}(y_2) \;-\; \mathrm{restriction}_{X_3 \to X_1}(y_3).
317	  \]
318	\end{lemma}
319	
320	\begin{proof}
321	  \uses{def:Scheme_HModule_prime_fromBiprod}
322	  \leanok
323	  Follows from the definition of $\fromBiprod$ as a biproduct desc and the concrete description of the biproduct isomorphism.
324	\end{proof}
325	
326	\begin{lemma}\leanok
327	[$\Ext$ biproduct bridge for $\toBiprod$]
328	  \label{lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
329	  \lean{AlgebraicGeometry.Scheme.HModule'_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
330	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_shortComplex}
331	  Bridges the abelian-group biproduct isomorphism and the $\Ext$ biproduct additivity for the $\toBiprod$ morphism.
332	\end{lemma}
333	
334	\begin{proof}
335	  \uses{lem:Scheme_HModule_prime_toBiprod_apply}
336	  \leanok
337	  Injects through the additive equivalence and closes by categorical discharge.
338	\end{proof}
339	
340	\begin{lemma}\leanok
341	[$\Ext$ biproduct bridge for $\fromBiprod$]
342	  \label{lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
343	  \lean{AlgebraicGeometry.Scheme.HModule'_mk₀_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
344	  \uses{def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_shortComplex}
345	  Bridges the same machinery for the $\fromBiprod$ morphism.
346	\end{lemma}
347	
348	\begin{proof}
349	  \uses{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
350	  \leanok
351	  Obtains a pair from the biproduct surjectivity, then rewrites through the concrete formulas and closes by categorical discharge.
352	\end{proof}
353	
354	\begin{definition}\leanok
355	[Comparison isomorphism]
356	  \label{def:Scheme_HModule_prime_sequenceIso}
357	  \lean{AlgebraicGeometry.Scheme.HModule'_sequenceIso}
358	  \uses{def:Scheme_HModule_prime_sequence, lem:Scheme_HModule_prime_shortComplex_shortExact, lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply, lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
359	  The Mayer--Vietoris sequence of Definition~\ref{def:Scheme_HModule_prime_sequence} is canonically isomorphic to the $\Ext$ contravariant sequence applied to the short exact sequence of Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_shortExact}.
360	\end{definition}
361	
362	\begin{proof}
363	  \uses{lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply, lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
364	  \leanok
365	  The isomorphism is built componentwise: identity maps on the bare terms, and the composition of the biproduct isomorphism with the $\Ext$ biproduct additivity (in the appropriate direction) on the biproduct terms. The five compatibility squares close via the four auxiliary lemmas above and the definition of the connecting homomorphism.
366	\end{proof}
367	
368	\subsection{Exactness}
369	
370	% NOTE: classical Mayer--Vietoris long exact sequence in sheaf
371	% cohomology; see Hartshorne, *Algebraic Geometry*, Ex.~III.4.6
372	% (TOC: `references/hartshorne-ag.md`) and Stacks Tag~\textbf{03B0}
373	% (Section 21.50 ``Mayer-Vietoris''). The abstract / $k$-module-valued
374	% repackaging here mirrors Mathlib's
375	% \texttt{CategoryTheory.MayerVietorisSquare} infrastructure.
376	\begin{theorem}\leanok
377	[Mayer--Vietoris exactness]
378	  \label{thm:Scheme_HModule_prime_sequence_exact}
379	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence_exact}
380	  \uses{def:Scheme_HModule_prime_sequence, def:Scheme_HModule_prime_sequenceIso}
381	  The Mayer--Vietoris sequence of Definition~\ref{def:Scheme_HModule_prime_sequence} is exact.
382	\end{theorem}
383	
384	\begin{proof}
385	  \uses{def:Scheme_HModule_prime_sequenceIso}
386	  \leanok
387	  Transport exactness along the comparison isomorphism of Definition~\ref{def:Scheme_HModule_prime_sequenceIso}. The $\Ext$ contravariant sequence is exact by the general exactness theorem for $\Ext$ applied to a short exact sequence.
388	\end{proof}
389	
390	\begin{lemma}\leanok
391	[Connecting homomorphism annihilates $\toBiprod$]
392	  \label{lem:Scheme_HModule_prime_delta_toBiprod}
393	  \lean{AlgebraicGeometry.Scheme.HModule'_δ_toBiprod}
394	  \uses{thm:Scheme_HModule_prime_sequence_exact}
395	  In the setting above,
396	  \[
397	    \delta \circ \toBiprod \;=\; 0.
398	  \]
399	\end{lemma}
400	
401	\begin{proof}
402	  \uses{thm:Scheme_HModule_prime_sequence_exact}
403	  \leanok
404	  Immediate from exactness at the third term of the sequence.
