582	\end{definition}
583	
584	\begin{definition}\leanok
585	[Parameterised \v{C}ech cohomology]
586	  \label{def:Scheme_cechCohomology}
587	  \lean{AlgebraicGeometry.Scheme.cechCohomology}
588	  \uses{def:Scheme_cechCochain}
589	  With $(C, F, \mathcal U)$ as in Definition~\ref{def:Scheme_cechCochain}, define the $n$-th \v{C}ech cohomology to be the $n$-th homology of the \v{C}ech cochain complex.
590	\end{definition}
591	
592	\begin{theorem}\leanok
593	[\v{C}ech complex bridge to structure-sheaf specialisation]
594	  \label{thm:Scheme_cechCochain_OC_eq}
