602	  \label{thm:Scheme_cechCohomology_OC_eq}
603	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC_eq}
604	  \uses{def:Scheme_cechCohomology, def:Scheme_cechCohomology_OC}
